dslRule:
/*!id: jdt.internal.performance.empty-string-constructor-to-constant*/
/*!description: Replaces the no-argument String constructor with the internal Util.EMPTY_STRING constant for performance and consistency.*/
/*!severity: info*/
new java.lang.String()
=> org.eclipse.jdt.internal.compiler.util.Util.EMPTY_STRING
;;

/*!id: jdt.internal.importrewrite.concatenate-name-to-util*/
/*!description: Replaces internal concatenateName helper with Util.concatenateName to standardize name concatenation in ImportRewrite.*/
/*!severity: info*/
/*!minJavaVersion: 8*/
/*!tags: jdt, internal, refactoring*/
concatenateName($arg1, $arg2)
=> org.eclipse.jdt.internal.core.util.Util.concatenateName($arg1, $arg2, '.')
;;

/*!id: jdt.internal.importrewriteanalyzer.constructor.add-containernamelength*/
/*!description: Updates the internal ImportDeclEntry constructor to include containerNameLength, derived from the element name.*/
/*!severity: info*/
/*!minJavaVersion: 8*/
new org.eclipse.jdt.internal.core.dom.rewrite.ImportRewriteAnalyzer.ImportDeclEntry($elementName, $isStatic, $sourceRange)
=> new org.eclipse.jdt.internal.core.dom.rewrite.ImportRewriteAnalyzer.ImportDeclEntry(getContainerNameLength($elementName), $elementName, $isStatic, $sourceRange)
;;

/*!id: jdt.internal.importrewriteanalyzer.method.getsimplename-to-gettypequalifiedname*/
/*!description: Replaces getSimpleName() with getTypeQualifiedName() on ImportDeclEntry for more precise name extraction based on new container length information.*/
/*!severity: info*/
/*!minJavaVersion: 8*/
org.eclipse.jdt.internal.core.dom.rewrite.ImportRewriteAnalyzer.ImportDeclEntry.$curr.getSimpleName()
=> org.eclipse.jdt.internal.core.dom.rewrite.ImportRewriteAnalyzer.ImportDeclEntry.$curr.getTypeQualifiedName()
;;

dslRuleAfterChange:
/* Example of what a DSL rule might look like with new features, NOT currently supported */
// Rule 1: Add ensureSpaceAfterReplace after rewriteRequiredNode for return types
rewriteRequiredNode($node, $property) :: $property == org.eclipse.jdt.core.dom.MethodDeclaration.RETURN_TYPE_PROPERTY
=>
rewriteRequiredNode($node, $property);
ensureSpaceAfterReplace($node, $property);
;;

// Rule 2: Add ensureSpaceAfterReplace after rewriteRequiredNode for field types
rewriteRequiredNode($node, org.eclipse.jdt.core.dom.FieldDeclaration.TYPE_PROPERTY)
=>
rewriteRequiredNode($node, org.eclipse.jdt.core.dom.FieldDeclaration.TYPE_PROPERTY);
ensureSpaceAfterReplace($node, org.eclipse.jdt.core.dom.FieldDeclaration.TYPE_PROPERTY);
;;

// Rule 3: Insert conditional ensureSpaceAfterReplace for single variable declarations
// This pattern requires matching an existing statement and inserting new conditional logic before it.
// This is NOT expressible with current DSL replacement mechanisms.
